enum WireStatus { WIRE_EMPTY = 0, WIRE_RETURNED = 1, WIRE_SIGNAL = 2 };
struct ParsedObject { char id[BINORACLE_MAX_OBJECT_ID]; size_t size; int place_right; unsigned char bytes[BINORACLE_MAX_OBJECT_BYTES]; };
struct ParsedCase { uint64_t gpr[6]; int gpr_object[6]; int gpr_null[6]; unsigned int gpr_object_index[6]; size_t object_count; struct ParsedObject objects[BINORACLE_MAX_OBJECTS]; size_t virtual_read_size; unsigned char virtual_read[BINORACLE_MAX_VIRTUAL_READ_BYTES]; };
struct SharedResult { volatile sig_atomic_t status, signal_number; uintptr_t fault_address; uint64_t return_rax, return_rdx, elapsed_us; uintptr_t object_address[BINORACLE_MAX_OBJECTS], left_guard_start[BINORACLE_MAX_OBJECTS], left_guard_end[BINORACLE_MAX_OBJECTS], right_guard_start[BINORACLE_MAX_OBJECTS], right_guard_end[BINORACLE_MAX_OBJECTS]; unsigned char object_after[BINORACLE_MAX_OBJECTS][BINORACLE_MAX_OBJECT_BYTES]; size_t global_count, global_size[BINORACLE_MAX_GLOBALS]; unsigned char global_before[BINORACLE_MAX_GLOBALS][BINORACLE_MAX_GLOBAL_BYTES], global_after[BINORACLE_MAX_GLOBALS][BINORACLE_MAX_GLOBAL_BYTES]; volatile size_t external_event_count; volatile int external_events_truncated; struct BinOracleExternalEvent external_events[BINORACLE_MAX_EXTERNAL_EVENTS]; };
static struct SharedResult *signal_result;

static void signal_handler(int sig, siginfo_t *info, void *context) { (void)context; if (signal_result) { signal_result->status = WIRE_SIGNAL; signal_result->signal_number = sig; signal_result->fault_address = info ? (uintptr_t)info->si_addr : 0; } _exit(128 + sig); }
static const char *find_key(const char *json, const char *key) { char pattern[96]; if (snprintf(pattern, sizeof(pattern), "\"%s\"", key) < 0) return NULL; const char *found = strstr(json, pattern); return found ? strchr(found + strlen(pattern), ':') : NULL; }
static int parse_uint(const char *json, const char *key, uint64_t *out) { const char *v=find_key(json,key); char *end; if (!v) return 0; while (isspace((unsigned char)*++v)); if (*v=='{') return 2; errno=0; long long n=strtoll(v,&end,0); if(errno || end==v) return -1; *out=(uint64_t)n; return 1; }
static int parse_string(const char *json, const char *key, char *out, size_t cap) { const char *v=find_key(json,key); if(!v)return 0; while(isspace((unsigned char)*++v)); if(*v++!='\"')return -1; const char *end=strchr(v,'\"'); if(!end || (size_t)(end-v)>=cap)return -1; memcpy(out,v,(size_t)(end-v)); out[end-v]=0; return 1; }
static int decode_hex(const char *hex, unsigned char *out, size_t size) { for(size_t i=0;i<size;i++){ unsigned char a=(unsigned char)tolower((unsigned char)hex[i*2]),b=(unsigned char)tolower((unsigned char)hex[i*2+1]); int hi=isdigit(a)?a-'0':a-'a'+10,lo=isdigit(b)?b-'0':b-'a'+10; if(hi<0||hi>15||lo<0||lo>15)return -1; out[i]=(unsigned char)((hi<<4)|lo); } return 0; }
static const char *object_value(const char *objects, const char *id) { char pat[BINORACLE_MAX_OBJECT_ID+4]; if(snprintf(pat,sizeof(pat),"\"%s\"",id)<0)return NULL; const char *p=strstr(objects,pat); return p ? strchr(p+strlen(pat), ':') : NULL; }
static int parse_case(const char *json, struct ParsedCase *p) { static const char *regs[6]={"RDI","RSI","RDX","RCX","R8","R9"}; memset(p,0,sizeof(*p)); const char *gprs=find_key(json,"gpr"); const char *objects=find_key(json,"objects"); if(!gprs) gprs=json; for(size_t i=0;i<6;i++){ uint64_t n; int r=parse_uint(gprs,regs[i],&n); if(r<0)return -1; p->gpr[i]=n; if(r==2){ const char *v=find_key(gprs,regs[i]); char ref[BINORACLE_MAX_OBJECT_ID]; if(v && parse_string(v,"object_ref",ref,sizeof(ref))==1){ p->gpr_object[i]=1; size_t j; for(j=0;j<p->object_count;j++)if(!strcmp(p->objects[j].id,ref))break; if(j==p->object_count){ if(j>=BINORACLE_MAX_OBJECTS)return -1; const char *o=objects ? object_value(objects,ref) : strstr(json,"\"obj0\""); uint64_t sz; char hex[BINORACLE_MAX_OBJECT_BYTES*2+1], placement[16]="right"; if(!o||parse_uint(o,"size",&sz)!=1||sz==0||sz>BINORACLE_MAX_OBJECT_BYTES||parse_string(o,"bytes_hex",hex,sizeof(hex))!=1||strlen(hex)!=(size_t)sz*2||decode_hex(hex,p->objects[j].bytes,(size_t)sz))return -1; if(parse_string(o,"placement",placement,sizeof(placement))<0)return -1; snprintf(p->objects[j].id,sizeof(p->objects[j].id),"%s",ref); p->objects[j].size=(size_t)sz; p->objects[j].place_right=strcmp(placement,"left")!=0; p->object_count++; } p->gpr_object_index[i]=(unsigned int)j; } else if(v && strstr(v,"\"null\""))p->gpr_null[i]=1; else return -1; }} const char *stream=find_key(json,"virtual_read_bytes"); if(stream){ char hex[BINORACLE_MAX_VIRTUAL_READ_BYTES*2+1]; if(parse_string(json,"virtual_read_bytes",hex,sizeof(hex))!=1||strlen(hex)%2)return -1; p->virtual_read_size=strlen(hex)/2; if(decode_hex(hex,p->virtual_read,p->virtual_read_size))return -1; } /* Legacy V1 input without gpr/objects. */ if(!p->object_count){ const char *o=strstr(json,"\"obj0\""); if(o){ uint64_t sz; char hex[BINORACLE_MAX_OBJECT_BYTES*2+1], placement[16]="right"; if(parse_uint(o,"size",&sz)!=1||!sz||sz>BINORACLE_MAX_OBJECT_BYTES||parse_string(o,"bytes_hex",hex,sizeof(hex))!=1||strlen(hex)!=(size_t)sz*2||decode_hex(hex,p->objects[0].bytes,(size_t)sz))return -1; (void)parse_string(o,"placement",placement,sizeof(placement)); strcpy(p->objects[0].id,"obj0"); p->objects[0].size=(size_t)sz;p->objects[0].place_right=strcmp(placement,"left")!=0;p->object_count=1; for(size_t i=0;i<6;i++)if(p->gpr_object[i])p->gpr_object_index[i]=0; }} return 0; }
static char *read_stdin(void) { size_t cap=4096,n=0; char *d=malloc(cap); if(!d)return NULL; for(;;){if(n+2049>cap){cap*=2;if(cap>1024*1024){free(d);return NULL;}char *x=realloc(d,cap);if(!x){free(d);return NULL;}d=x;}ssize_t k=read(STDIN_FILENO,d+n,cap-n-1);if(k<0){free(d);return NULL;}if(!k)break;n+=(size_t)k;}d[n]=0;return d; }
static void limits(void) { struct rlimit cpu={1,1},as={256U*1024U*1024U,256U*1024U*1024U},fs={1024U*1024U,1024U*1024U}; (void)setrlimit(RLIMIT_CPU,&cpu);(void)setrlimit(RLIMIT_AS,&as);(void)setrlimit(RLIMIT_FSIZE,&fs); }
static void child_run(const struct ParsedCase *p, struct SharedResult *s) { signal_result=s; struct sigaction a;memset(&a,0,sizeof(a));a.sa_sigaction=signal_handler;a.sa_flags=SA_SIGINFO|SA_RESETHAND;sigemptyset(&a.sa_mask); int sigs[]={SIGSEGV,SIGBUS,SIGILL,SIGFPE,SIGABRT};for(size_t i=0;i<5;i++)(void)sigaction(sigs[i],&a,NULL);limits();int fd=open("/dev/null",O_WRONLY);if(fd>=0){(void)dup2(fd,1);(void)dup2(fd,2);close(fd);}struct GuardObject o[BINORACLE_MAX_OBJECTS];memset(o,0,sizeof(o));for(size_t i=0;i<p->object_count;i++){if(binoracle_guard_allocate(&o[i],p->objects[i].size,p->objects[i].place_right))_exit(120);memcpy(o[i].payload,p->objects[i].bytes,p->objects[i].size);s->object_address[i]=(uintptr_t)o[i].payload;s->left_guard_start[i]=(uintptr_t)o[i].mapping;s->left_guard_end[i]=(uintptr_t)o[i].accessible;s->right_guard_start[i]=(uintptr_t)o[i].accessible+o[i].accessible_size;s->right_guard_end[i]=s->right_guard_start[i]+o[i].page_size;}s->global_count=binoracle_global_count>BINORACLE_MAX_GLOBALS?BINORACLE_MAX_GLOBALS:binoracle_global_count;for(size_t i=0;i<s->global_count;i++){s->global_size[i]=binoracle_globals[i].size>BINORACLE_MAX_GLOBAL_BYTES?BINORACLE_MAX_GLOBAL_BYTES:binoracle_globals[i].size;memcpy(s->global_before[i],binoracle_globals[i].address,s->global_size[i]);}struct CallFrame f;memset(&f,0,sizeof(f));for(size_t i=0;i<6;i++)f.gpr[i]=p->gpr_object[i]?(uint64_t)(uintptr_t)o[p->gpr_object_index[i]].payload:p->gpr[i];f.target=binoracle_target_address();binoracle_stubs_configure(p->virtual_read,p->virtual_read_size);binoracle_stubs_set_event_sink(s->external_events,BINORACLE_MAX_EXTERNAL_EVENTS,&s->external_event_count,&s->external_events_truncated);binoracle_stubs_enable(1);uint64_t start=binoracle_now_us();binoracle_call(&f);s->elapsed_us=binoracle_now_us()-start;binoracle_stubs_enable(0);s->return_rax=f.return_rax;s->return_rdx=f.return_rdx;for(size_t i=0;i<p->object_count;i++)memcpy(s->object_after[i],o[i].payload,p->objects[i].size);for(size_t i=0;i<s->global_count;i++)memcpy(s->global_after[i],binoracle_globals[i].address,s->global_size[i]);s->status=WIRE_RETURNED;for(size_t i=0;i<p->object_count;i++)binoracle_guard_release(&o[i]);_exit(0); }
static const char *sig_name(int n){switch(n){case SIGSEGV:return "SIGSEGV";case SIGBUS:return "SIGBUS";case SIGILL:return "SIGILL";case SIGFPE:return "SIGFPE";case SIGABRT:return "SIGABRT";case SIGKILL:return "SIGKILL";default:return "UNKNOWN";}}
static void hex(const unsigned char *d,size_t n){char *x=malloc(n*2+1);if(!x)return;binoracle_hex_encode(d,n,x);fputs(x,stdout);free(x);}
static int object_at(const struct ParsedCase *p,const struct SharedResult *s,uintptr_t address,const char **klass,int64_t *relative){for(size_t i=0;i<p->object_count;i++){*relative=(int64_t)(address-s->object_address[i]);if(address>=s->left_guard_start[i]&&address<s->left_guard_end[i]){*klass="left_guard";return (int)i;}if(address>=s->right_guard_start[i]&&address<s->right_guard_end[i]){*klass="right_guard";return (int)i;}if(address>=s->object_address[i]&&address<s->object_address[i]+p->objects[i].size){*klass="payload";return (int)i;}}return -1;}
static void print_external_events(const struct SharedResult *s) { size_t count=s->external_event_count; if(count>BINORACLE_MAX_EXTERNAL_EVENTS)count=BINORACLE_MAX_EXTERNAL_EVENTS; fputs("\"external_events\":[",stdout); for(size_t i=0;i<count;i++){const struct BinOracleExternalEvent *event=&s->external_events[i];if(i)fputc(',',stdout);if(event->kind==1U){fputs("{\"kind\":\"puts\",\"sequence\":",stdout);printf("%u,\"text_hex\":",event->sequence);fputc('\"',stdout);hex(event->text,event->text_size);fputs("\",\"text_truncated\":",stdout);fputs(event->text_truncated?"true}":"false}",stdout);}else{fputs("{\"kind\":\"read\",\"sequence\":",stdout);printf("%u,\"fd\":%d,\"requested\":%zu,\"returned\":%zu,\"data_hex\":\"",event->sequence,event->fd,event->requested,event->returned);hex(event->data,event->data_size);fputs("\",\"data_truncated\":",stdout);fputs(event->data_truncated?"true}":"false}",stdout);}}fputs("],\"external_events_truncated\":",stdout);fputs(s->external_events_truncated?"true":"false",stdout); }
static void print_result(const struct ParsedCase *p,const struct SharedResult *s,int timeout,int ws){const char *status=timeout?"timeout":s->status==WIRE_RETURNED?"returned":s->status==WIRE_SIGNAL||WIFSIGNALED(ws)?"signal":"runner_error";int sn=s->signal_number;if(!sn&&WIFSIGNALED(ws))sn=WTERMSIG(ws);printf("{\"status\":\"%s\",\"signal\":",status);if(sn)printf("\"%s\"",sig_name(sn));else fputs("null",stdout);const char *cl="outside_known_object";int64_t rel=0;int oi=s->status==WIRE_SIGNAL?object_at(p,s,s->fault_address,&cl,&rel):-1;if(oi>=0)printf(",\"fault_address_class\":\"obj%u_%s\",\"object\":\"%s\",\"relative_offset\":%lld",(unsigned)oi,cl,p->objects[oi].id,(long long)rel);else fputs(",\"fault_address_class\":null,\"object\":null,\"relative_offset\":null",stdout);int ri=-1; for(size_t i=0;i<p->object_count;i++){uintptr_t begin=s->object_address[i],end=begin+p->objects[i].size;if((uintptr_t)s->return_rax>=begin&&(uintptr_t)s->return_rax<=end){ri=(int)i;rel=(int64_t)((uintptr_t)s->return_rax-begin);break;}}printf(",\"return\":{\"rax\":%llu,\"rdx\":%llu,\"object\":",(unsigned long long)s->return_rax,(unsigned long long)s->return_rdx);if(ri>=0)printf("\"%s\",\"offset\":%lld}",p->objects[ri].id,(long long)rel);else fputs("null,\"offset\":null}",stdout);fputs(",\"objects\":{",stdout);if(s->status==WIRE_RETURNED)for(size_t i=0;i<p->object_count;i++){if(i)fputc(',',stdout);printf("\"%s\":{\"before_hex\":\"",p->objects[i].id);hex(p->objects[i].bytes,p->objects[i].size);fputs("\",\"after_hex\":\"",stdout);hex(s->object_after[i],p->objects[i].size);fputs("\"}",stdout);}fputs("},\"globals\":{",stdout);if(s->status==WIRE_RETURNED)for(size_t i=0;i<s->global_count;i++){if(i)fputc(',',stdout);printf("\"%s\":{\"before_hex\":\"",binoracle_globals[i].name);hex(s->global_before[i],s->global_size[i]);fputs("\",\"after_hex\":\"",stdout);hex(s->global_after[i],s->global_size[i]);fputs("\"}",stdout);}fputs("},",stdout);print_external_events(s);printf(",\"elapsed_us\":%llu}\n",(unsigned long long)s->elapsed_us);}
int main(int argc,char **argv){unsigned long timeout=100;if(argc==3&&!strcmp(argv[1],"--timeout-ms")){timeout=strtoul(argv[2],NULL,10);if(!timeout||timeout>10000){fputs("invalid timeout\n",stderr);return 2;}}char *json=read_stdin();struct ParsedCase p;if(!json||parse_case(json,&p)){free(json);fputs("invalid InputCase JSON\n",stderr);return 2;}free(json);struct SharedResult *s=mmap(NULL,sizeof(*s),PROT_READ|PROT_WRITE,MAP_SHARED|MAP_ANONYMOUS,-1,0);if(s==MAP_FAILED){perror("mmap");return 2;}memset(s,0,sizeof(*s));pid_t child=fork();if(child<0){perror("fork");munmap(s,sizeof(*s));return 2;}if(!child)child_run(&p,s);int ws=0,to=0;uint64_t deadline=binoracle_now_us()+timeout*1000ULL;for(;;){pid_t w=waitpid(child,&ws,WNOHANG);if(w==child||w<0)break;if(binoracle_now_us()>=deadline){to=1;(void)kill(child,SIGKILL);(void)waitpid(child,&ws,0);break;}struct timespec pause={0,1000000L};(void)nanosleep(&pause,NULL);}print_result(&p,s,to,ws);munmap(s,sizeof(*s));return 0;}
